// generate-history.ts 핵심 로직 (pseudocode)
function generateHistory(structuredCase, templateKey, cc):
  templateData = loadTemplate(templateKey) if templateKey else null
  historyTemplate = templateData?.history ?? null

  if historyTemplate is null:
    return buildHistoryDraft(structuredCase)  // 기존 폴백

  historyInputs = structuredCase.inputs.filter(i => i.sections.includes('history'))
  [corrections, styleRules] = await Promise.all([
    loadCorrections(cc, 'history'),
    loadStyleRules(cc, 'history')
  ])

  systemPrompt = GENERATE_HISTORY_SYSTEM_PROMPT
  if styleRules.length > 0: append rules to systemPrompt

  promptData = { historyInputs, ccSpecificFields (structuredCase minus inputs), historyTemplate }
  if corrections.length > 0: promptData.correctionExamples = corrections

  result = await generateText(JSON.stringify(promptData), systemPrompt, 2000)
  return result

// buildHistoryDraft는 route.ts에서 이 파일로 이동 (폴백용)
function buildHistoryDraft(structured):
  past = structured?.past_history?.join(', ') || '(-)'
  med = structured?.medication_history?.join(', ') || '(-)'
  op = structured?.operation_history?.join(', ') || '(-)'
  family = structured?.family_history
  lines = ['Past Hx. : ' + past, 'Med Hx. : ' + med, 'Op Hx. : ' + op]
  if family && family.length > 0: lines.push('Family Hx. : ' + family.join(', '))
  return lines.join('\n')

// generate-history.md: generate-pe.md 구조 참조
